sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({
    api,
    event,
    helpers,
    imports
}) {

    api.emit('CTRL_NEXTFORM#FIELD_VALUE_CHANGED');
    //used deep clone before. I think that's unneccessary
    const name = event.payload.fieldName;
    const prev = api.state.fields[name];
    if (prev === undefined) {
        console.warn("Set Field Value: issue with payload");
        return;
    }
    const newFields = {
        ...api.state.fields,
        [name]: {
            ...prev,
            value: event.payload.value,
            displayValue: event.payload.displayValue,
        },
    };
    api.setState('fields', newFields);

    api.setState('nextFormData', { ...api.state.nextFormData,
        fields: newFields
    });
}
